import { evaluateTime, evaluateSolar, evaluateLux, evaluateCondition } from './.homeybuild/src/lib/engine/conditionEvaluators.js';

// Test 1: Time condition - 08:00 should trigger if in window
const now = new Date('2025-01-15T08:30:00');
const lastEval = new Date('2025-01-15T08:00:00'); // exclusive lower bound
const beforeLast = new Date('2025-01-15T07:59:00');

const timeCond = { type: 'time', at: '08:15' };
const result1 = evaluateTime(timeCond, lastEval, now);
console.log('Test 1 - Time 08:15 in window (08:00, 08:30]:', result1.triggered ? 'PASS' : 'FAIL');

const result2 = evaluateTime(timeCond, beforeLast, new Date('2025-01-15T08:14:00'));
console.log('Test 2 - Time 08:15 should NOT trigger if now is 08:14:', !result2.triggered ? 'PASS' : 'FAIL');

// Test 3: Solar condition with Amsterdam coords
const solarCond = { type: 'solar', event: 'sunrise', offsetMinutes: 0 };
const result3 = evaluateSolar(solarCond, new Date('2025-01-15T00:00:00'), new Date('2025-01-15T23:59:59'), 52.3676, 4.9041);
console.log('Test 3 - Solar sunrise in Amsterdam:', result3.triggered ? 'PASS' : 'FAIL');

// Test 4: Lux condition - lt
const luxCond = { type: 'lux', operator: 'lt', value: 100 };
const result4 = evaluateLux(luxCond, 50, new Date());
console.log('Test 4 - Lux 50 < 100:', result4.triggered ? 'PASS' : 'FAIL');

// Test 5: Lux condition - gt
const luxCond2 = { type: 'lux', operator: 'gt', value: 100 };
const result5 = evaluateLux(luxCond2, 150, new Date());
console.log('Test 5 - Lux 150 > 100:', result5.triggered ? 'PASS' : 'FAIL');

// Test 6: Lux null should not trigger
const result6 = evaluateLux(luxCond, null, new Date());
console.log('Test 6 - Lux null:', !result6.triggered ? 'PASS' : 'FAIL');

console.log('All basic tests complete');
"

