import { evaluateTime, evaluateSolar, evaluateLux, evaluateCondition } from './.homeybuild/src/lib/engine/conditionEvaluators.js';

const now = new Date('2025-01-15T08:30:00');
const lastEval = new Date('2025-01-15T08:00:00');

// Test 1: Time condition
const timeCond = { type: 'time', at: '08:15' };
const result1 = evaluateTime(timeCond, lastEval, now);
console.log('Test 1 - Time 08:15 in window (08:00, 08:30]:', result1.triggered ? 'PASS' : 'FAIL');

// Test 2: Solar condition with Amsterdam coords
const solarCond = { type: 'solar', event: 'sunrise', offsetMinutes: 0 };
const result2 = evaluateSolar(solarCond, new Date('2025-01-15T00:00:00'), new Date('2025-01-15T23:59:59'), 52.3676, 4.9041);
console.log('Test 2 - Solar sunrise in Amsterdam:', result2.triggered ? 'PASS' : 'FAIL');

// Test 3: Lux condition - lt
const luxCond = { type: 'lux', operator: 'lt', value: 100 };
const result3 = evaluateLux(luxCond, 50, new Date());
console.log('Test 3 - Lux 50 < 100:', result3.triggered ? 'PASS' : 'FAIL');

// Test 4: Lux condition - gt
const luxCond2 = { type: 'lux', operator: 'gt', value: 100 };
const result4 = evaluateLux(luxCond2, 150, new Date());
console.log('Test 4 - Lux 150 > 100:', result4.triggered ? 'PASS' : 'FAIL');

// Test 5: Lux null should not trigger
const result5 = evaluateLux(luxCond, null, new Date());
console.log('Test 5 - Lux null:', !result5.triggered ? 'PASS' : 'FAIL');

// Test 6: evaluateCondition dispatcher for time
const result6 = evaluateCondition(timeCond, { now, lux: null, latitude: 52.3676, longitude: 4.9041, countryCode: 'NL' }, lastEval);
console.log('Test 6 - evaluateCondition dispatcher (time):', result6.triggered ? 'PASS' : 'FAIL');

// Test 7: evaluateCondition dispatcher for lux
const result7 = evaluateCondition(luxCond, { now: new Date(), lux: 50, latitude: 52.3676, longitude: 4.9041, countryCode: 'NL' }, lastEval);
console.log('Test 7 - evaluateCondition dispatcher (lux):', result7.triggered ? 'PASS' : 'FAIL');

// Test 8: Solar with offset
const solarWithOffset = { type: 'solar', event: 'sunset', offsetMinutes: -30 };
const result8 = evaluateSolar(solarWithOffset, new Date('2025-01-15T00:00:00'), new Date('2025-01-15T23:59:59'), 52.3676, 4.9041);
console.log('Test 8 - Solar sunset -30min offset:', result8.triggered ? 'PASS' : 'FAIL');

console.log('All tests complete');
"
